// Классификация входящего сообщения или callback_query
const update = $input.first().json;

let route = 'other';
let user_id = null;
let message_id = null;
let text = '';
let is_forwarded = false;

if (update.callback_query) {
  const cq = update.callback_query;
  user_id = cq.from.id;
  message_id = cq.message ? cq.message.message_id : null;
  text = cq.data || '';
  if (text === 'cmd_done') route = 'done';
  else if (text === 'cmd_goal' || text === 'cmd_status') route = 'goal';
  else if (text === 'cmd_fraud') route = 'fraud';
  else if (text === 'cmd_payday') route = 'payday';
  else if (text === 'cmd_reset') route = 'reset';
  else if (text === 'cmd_test') route = 'test';
  else if (text === 'cmd_help') route = 'help';
  else if (text === 'cmd_settings') route = 'settings';
  else if (text.startsWith('setv_')) route = 'set_value';
  // Sprint 1.3: /schedule + inline buttons routing (СПЕЦИФИЧЕСКИЕ ПЕРЕД generic)
  else if (text === 'cmd_set_schedule_preset') route = 'schedule_show_presets';
  else if (text === 'cmd_set_remind_0' || text === 'cmd_set_remind_3') route = 'schedule_set_remind';
  else if (text === 'cmd_schedule_pause_month') route = 'schedule_pause';
  else if (text === 'cmd_schedule_resume') route = 'schedule_resume';
  else if (text.startsWith('schv_')) route = 'schedule_set_preset';
  else if (text.startsWith('sch_')) route = 'sch_action';
  // Sprint 2.0: schedule v2 — новый flow с 4-кнопочным UI
  else if (text.startsWith('sch_')) route = 'sch_action';
  // Generic set_callback для settings — ПОСЛЕ schedule
  else if (text.startsWith('cmd_set_')) route = 'set_callback';
  else if (text.startsWith('dash_') || text === 'cmd_dashboard') route = 'today';
  else if (text === 'cmd_today') route = 'today';
  else if (text === 'cmd_plan') route = 'plan';
  else if (text === 'cmd_share') route = 'share';
  else if (text === 'cmd_iis3') route = 'iis3';
  else if (text === 'cmd_setup') route = 'setup';
  else if (text === 'cmd_ask') route = 'ask';
}
else if (update.message) {
  const msg = update.message;
  user_id = msg.from.id;
  message_id = msg.message_id;
  text = (msg.text || msg.caption || '').trim();
  // Проверяем forwarded сообщение
  is_forwarded = !!(msg.forward_from || msg.forward_from_chat || msg.forward_sender_name || msg.forward_signature);
  if (text.startsWith('/')) {
    if (text === '/start' || text.startsWith('/start@')) route = 'start';
    else if (text === '/done' || text.startsWith('/done@')) route = 'done';
    else if (text === '/goal' || text.startsWith('/goal@')) route = 'goal';
    else if (text === '/status' || text.startsWith('/status@')) route = 'goal';
    else if (text === '/today' || text.startsWith('/today@')) route = 'today';
    else if (text === '/dashboard' || text.startsWith('/dashboard@')) route = 'today';
    else if (text === '/plan' || text.startsWith('/plan@')) route = 'plan';
    else if (text === '/share' || text.startsWith('/share@')) route = 'share';
    else if (text === '/iis3' || text.startsWith('/iis3@')) route = 'iis3';
    else if (text === '/ask' || text.startsWith('/ask ') || text.startsWith('/ask@')) route = 'ask';
    else if (text === '/setup' || text.startsWith('/setup@')) route = 'setup';
    else if (text === '/fraud' || text.startsWith('/fraud@')) route = 'fraud';
    else if (text === '/help' || text.startsWith('/help@')) route = 'help';
    else if (text === '/reset' || text.startsWith('/reset@')) route = 'reset';
    else if (text === '/test' || text.startsWith('/test@')) route = 'test';
    else if (text === '/settings' || text.startsWith('/settings@')) route = 'settings';
    else if (text === '/schedule' || text.startsWith('/schedule@')) route = 'schedule';
    else if (text === '/digest' || text.startsWith('/digest@')) route = 'digest';
  } else if (is_forwarded && text.length >= 20) {
    // Forwarded сообщение → fraud-check
    route = 'fraud_inline';
  } else if (text.length >= 1) {
    // Любой свободный текст → ИИ-ассистент
    route = 'ask';
  }
}

return [{ json: { route, user_id, message_id, text, is_forwarded, update } }];

// Build body for /start reply with persistent profile + 8 inline buttons
const user_id = $('Classify').first().json.user_id;
const state = $('HTTP get_state').first().json.state;
const name = state._name || 'Инвестор';
const payday_day = state.payday_day || 5;
const monthly = state.monthly_amount || 15000;
const streak = state.current_streak || 0;
const goal = state.goal || {target_amount: 600000, current_amount: 0};
const pct = goal.target_amount > 0 ? Math.min(100, Math.round(goal.current_amount / goal.target_amount * 100)) : 0;
const is_default = name === 'Инвестор';

const greeting = is_default
  ? `👋 Привет! Я — Капитал, твой личный DCA-помощник.\n\nЧтобы начать, настрой профиль одной командой:\n/setup 5 15000 balanced 1000000 5.5 alfa A3\n\nФормат: payday день monthly риск цель сумма цель лет брокер тип_ИИС`
  : `👋 С возвращением, ${name}!\n\n📊 Твой профиль:\n• Payday: ${payday_day}-е число, ${monthly.toLocaleString('ru-RU')}₽/мес\n• Цель: ${goal.target_amount.toLocaleString('ru-RU')}₽ (${pct}%)\n• Streak: ${streak} мес 🔥\n\nЧто дальше?`;

const body = {
  chat_id: user_id,
  text: greeting,
  reply_markup: {
    inline_keyboard: [
      [{text: "📅 /today — сегодня и payday", callback_data: "cmd_today"}],
      [{text: "📋 /plan — план на месяц", callback_data: "cmd_plan"}],
      [{text: "✅ /done — засчитать payday", callback_data: "cmd_done"}, {text: "🎯 /goal", callback_data: "cmd_goal"}],
      [{text: "🏦 /iis3 — ИИС статус", callback_data: "cmd_iis3"}, {text: "📤 /share — карточка", callback_data: "cmd_share"}],
      [{text: "🔍 /fraud — проверить", callback_data: "cmd_fraud"}, {text: "⚙ /setup — настройки", callback_data: "cmd_setup"}],
      [{text: "❓ /help — все команды", callback_data: "cmd_help"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /done reply: streak + goal + прогноз
const user_id = $('Classify').first().json.user_id;
const streak = $('HTTP streak').first().json;
const goal = $('HTTP goal (for done)').first().json;
const state = $('HTTP get_state (2)').first().json.state;
const monthly = state.monthly_amount || 15000;
const target = (state.goal && state.goal.target_amount) || 600000;
const current = (state.goal && state.goal.current_amount) || 0;

const new_streak = streak.current_streak || 0;
const months_to_goal = monthly > 0 ? Math.max(1, Math.ceil((target - current) / monthly * 12 / 12)) : 0;
const future_with_yield = Math.round((current * 1.12) + (monthly * 12 * new_streak * 1.12 / 2));

let milestone_text = '';
if (streak.milestone === '3mo') milestone_text = '\n\n🎉 3 месяца подряд! +5% годовых vs нерегулярные.';
else if (streak.milestone === '6mo') milestone_text = '\n\n🔥 6 месяцев! Ты обогнал 70% инвесторов.';
else if (streak.milestone === '1y') milestone_text = '\n\n🏆 1 ГОД. Это уже не привычка — это характер.';

const body = {
  chat_id: user_id,
  text: streak.message + milestone_text + `\n\n📈 Прогноз: при ${monthly.toLocaleString('ru-RU')}₽/мес → цель ${target.toLocaleString('ru-RU')}₽ через ~${months_to_goal} мес`,
  reply_markup: {
    inline_keyboard: [
      [{text: "📤 Поделиться streak", callback_data: "cmd_share"}],
      [{text: "📋 План на следующий месяц", callback_data: "cmd_plan"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /goal reply
const user_id = $('Classify').first().json.user_id;
const goal = $('HTTP goal (for goal)').first().json;

const body = {
  chat_id: user_id,
  text: goal.message,
  reply_markup: {
    inline_keyboard: [
      [{text: "📤 Поделиться", callback_data: "cmd_share"}, {text: "🏦 ИИС-3", callback_data: "cmd_iis3"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /payday reply
const user_id = $('Classify').first().json.user_id;
const payday = $('HTTP payday').first().json;

const body = {
  chat_id: user_id,
  text: payday.message,
  reply_markup: {
    inline_keyboard: [
      [{text: "✅ Сделал /done", callback_data: "cmd_done"}],
      [{text: "📅 Добавить к вычету", callback_data: "cmd_iis3"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /today reply — short format
const user_id = $('Classify').first().json.user_id;
const today = $('HTTP today').first().json;

let text = today.text || today.message || '';
if (text && text.length > 400) {
  const widgets = text.split('\n\n');
  let count = 0;
  let result = [];
  for (const w of widgets) {
    result.push(w);
    if (w.match(/^\*\*[^*]+\*\*/)) count++;
    if (count >= 2) break;
  }
  text = result.join('\n\n') + '\n\n_Полный дашборд: https://ejgxa2qa9mpl.space.minimax.io_';
}

const body = {
  chat_id: user_id,
  text: text || '📊 Открой дашборд',
  reply_markup: today.reply_markup || {
    inline_keyboard: [
      [{text: '📊 Полный дашборд', url: 'https://ejgxa2qa9mpl.space.minimax.io'}],
      [{text: '📋 /plan', callback_data: 'cmd_plan'}, {text: '🏦 /iis3', callback_data: 'cmd_iis3'}]
    ]
  },
  parse_mode: 'Markdown',
  disable_web_page_preview: true
};
return [{ json: { body } }];

// Build body for /plan reply
const user_id = $('Classify').first().json.user_id;
const plan = $('HTTP plan').first().json;

const body = {
  chat_id: user_id,
  text: plan.message,
  reply_markup: {
    inline_keyboard: [
      [{text: "✅ Сделал по плану", callback_data: "cmd_done"}, {text: "🏦 /iis3", callback_data: "cmd_iis3"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /fraud_inline reply (or /fraud text)
const user_id = $('Classify').first().json.user_id;
const fraud = $('HTTP fraud').first().json;

const body = {
  chat_id: user_id,
  text: fraud.reply
};
// Only add reply_to_message_id if is_forwarded (for fraud_inline use case)
if ($('Classify').first().json.is_forwarded) {
  body.reply_to_message_id = $('Classify').first().json.message_id;
}
return [{ json: { body } }];

// Build body for /share reply
const user_id = $('Classify').first().json.user_id;
const share = $('HTTP share').first().json;

const body = {
  chat_id: user_id,
  text: share.card,
  reply_markup: {
    inline_keyboard: [
      [{text: "🔄 Обновить прогресс", callback_data: "cmd_goal"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /iis3 reply
const user_id = $('Classify').first().json.user_id;
const iis = $('HTTP iis3').first().json;

const body = {
  chat_id: user_id,
  text: iis.message,
  reply_markup: {
    inline_keyboard: [
      [{text: "📤 Поделиться", callback_data: "cmd_share"}],
      [{text: "📋 План на декабрь", callback_data: "cmd_plan"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /reset reply
const user_id = $('Classify').first().json.user_id;
const reset = $('HTTP reset').first().json;

const body = {
  chat_id: user_id,
  text: reset.message
};
return [{ json: { body } }];

// Handle /setup as text command (when user types /setup with params)
const user_id = $('Classify').first().json.user_id;
const full_text = $('Classify').first().json.text || '';
const match = full_text.match(/^\/setup\s+(\d+)\s+(\d+)\s+(\w+)\s+(\d+)\s+([\d.]+)\s+(\w+)\s+(\w+)/i);

if (!match) {
  const body = {
    chat_id: user_id,
    text: '❌ Неверный формат.\n\nПример:\n/setup 5 15000 balanced 1000000 5.5 alfa A3\n\nФормат: payday день monthly риск цель₽ лет брокер ИИС_тип'
  };
  return [{ json: { body } }];
}

const [, payday_day, monthly, risk, goal_amount, goal_years, broker, iis_type] = match;
return [{ json: {
  user_id,
  name: 'Инвестор',
  payday_day: parseInt(payday_day),
  monthly_amount: parseInt(monthly),
  risk_profile: risk.toLowerCase(),
  goal_amount: parseInt(goal_amount),
  goal_years: parseFloat(goal_years),
  broker: broker.toLowerCase(),
  iis_type: iis_type.toUpperCase()
} }];

// Reply to /setup with onboard result
const user_id = $('parse setup').first().json.user_id;
const onboard = $('HTTP onboard').first().json;
const state = onboard.state || {};

const body = {
  chat_id: user_id,
  text: onboard.message + '\n\n🎯 Твой план: payday ' + state.payday_day + '-е, ' + state.monthly_amount.toLocaleString('ru-RU') + '₽/мес, цель ' + (state.goal ? state.goal.target_amount.toLocaleString('ru-RU') : '?') + '₽ за ' + (state.goal ? state.goal.target_years : '?') + ' лет.\n\nПоехали! /start для главного меню.'
};
return [{ json: { body } }];

// Build body for /test reply: fraud + goal combined
const user_id = $('Classify').first().json.user_id;
const fraud = $('HTTP test_fraud').first().json;
const goal = $('HTTP test_goal').first().json;

const body = {
  chat_id: user_id,
  text: `✅ **Fraud check (типичный скам):**\n\n${fraud.message}\n\n🎯 **Goal:**\n${goal.message}`
};
return [{ json: { body } }];

// Build body for /ask reply (YandexGPT-ассистент) с RAG-lite
const user_id = $('Classify').first().json.user_id;
const ask = $('HTTP ask').first().json;
const is_freetext = !$('Classify').first().json.text.startsWith('/');

let body_text;
if (ask.ok) {
  body_text = (is_freetext ? '' : '🤖 ') + ask.reply;
} else {
  body_text = ask.reply || 'ИИ недоступен. Попробуй позже.';
}

const body = {
  chat_id: user_id,
  text: body_text,
  reply_markup: {
    inline_keyboard: [
      [{text: "📅 /today", callback_data: "cmd_today"}, {text: "📋 /plan", callback_data: "cmd_plan"}],
      [{text: "❓ /help", callback_data: "cmd_help"}]
    ]
  }
};
return [{ json: { body } }];

// /settings: v2 wizard
const user_id = $('Classify').first().json.user_id;
const menu_data = $('HTTP settings_menu').first().json;

let text = '⚙ **Настройки Капитала**\n\nВыбери что хочешь изменить:';
let reply_markup;
if (menu_data.v2) {
  text = menu_data.menu?.text || text;
  reply_markup = menu_data.menu?.reply_markup;
} else {
  const m = menu_data.menu || {};
  if (m.inline_keyboard) {
    reply_markup = { inline_keyboard: m.inline_keyboard };
  } else {
    reply_markup = m.reply_markup;
  }
}

const body = {
  chat_id: user_id,
  text: text,
  reply_markup: reply_markup,
  parse_mode: 'Markdown'
};
return [{ json: { body } }];

// /settings button: cmd_set_X → показать prompt + установить pending_setting
const user_id = $('Classify').first().json.user_id;
const cb = $('Classify').first().json.text;
const field = cb.replace('cmd_set_', '');
const state = $('HTTP get_state_set').first().json.state;
const current = state[field];

const prompts = {
  payday_day: '📅 Введи новый payday-день (1-31). Например: 10',
  monthly_amount: '💰 Введи новую сумму в месяц, ₽. Например: 20000',
  risk_profile: '⚖ Выбери профиль кнопкой ниже:',
  broker: '🏦 Выбери брокера кнопкой ниже:',
  iis_type: '🏛 Выбери тип ИИС кнопкой ниже:',
  _name: '👤 Введи имя:',
};
const prompt = prompts[field] || 'Введи значение:';

const keyboard = { inline_keyboard: [] };
if (field === 'risk_profile') {
  keyboard.inline_keyboard = [
    [{text: '🛡 Защитный', callback_data: 'setv_conservative'}],
    [{text: '⚖ Сбалансированный', callback_data: 'setv_balanced'}],
    [{text: '📈 Агрессивный', callback_data: 'setv_aggressive'}],
  ];
} else if (field === 'broker') {
  keyboard.inline_keyboard = [
    [{text: 'Т-Инвестиции', callback_data: 'setv_tinkoff'}, {text: 'Альфа', callback_data: 'setv_alfa'}],
    [{text: 'БКС', callback_data: 'setv_bcs'}, {text: 'Финам', callback_data: 'setv_finam'}],
    [{text: 'Сбер', callback_data: 'setv_sber'}, {text: 'Алор', callback_data: 'setv_alor'}],
  ];
} else if (field === 'iis_type') {
  keyboard.inline_keyboard = [
    [{text: 'ИИС А', callback_data: 'setv_A'}, {text: 'ИИС Б', callback_data: 'setv_B'}],
    [{text: 'ИИС-3', callback_data: 'setv_A3'}, {text: 'Без ИИС', callback_data: 'setv_none'}],
  ];
} else {
  keyboard.inline_keyboard = [[{text: '🚪 Отмена', callback_data: 'cmd_settings'}]];
}

const body = {
  chat_id: user_id,
  text: prompt + (current ? '\n\nСейчас: ' + (typeof current === 'object' ? JSON.stringify(current) : current) : ''),
  reply_markup: keyboard
};
return [{ json: { body, pending_field: field, current_value: current } }];

// Подтверждение изменения настройки
const user_id = $('Classify').first().json.user_id;
const result = $('HTTP set_save').first().json;

let body_text;
if (result.ok) {
  const new_val = result.state[result.field] || result.value;
  body_text = `✅ Готово! ${result.field} = ${new_val}\n\nИспользуй /settings для других изменений.`;
} else {
  body_text = `❌ Ошибка: ${result.error}`;
}

const body = {
  chat_id: user_id,
  text: body_text,
  reply_markup: {
    inline_keyboard: [
      [{text: "⚙ Ещё настройки", callback_data: "cmd_settings"}],
      [{text: "📅 /today", callback_data: "cmd_today"}]
    ]
  }
};
return [{ json: { body } }];

// /digest: показать weekly digest
const user_id = $('Classify').first().json.user_id;
const digest = $('HTTP digest').first().json;

const body = {
  chat_id: user_id,
  text: digest.text || 'Ошибка дайджеста',
  reply_markup: {
    inline_keyboard: [
      [{text: "📅 /today", callback_data: "cmd_today"}, {text: "📋 /plan", callback_data: "cmd_plan"}],
      [{text: "📤 /share", callback_data: "cmd_share"}]
    ]
  }
};
return [{ json: { body } }];

// Build body for /schedule reply with inline keyboard
const user_id = $('Classify').first().json.user_id;
const data = $('HTTP schedule').first().json;

const body = {
  chat_id: user_id,
  text: data.message,
  reply_markup: {
    inline_keyboard: data.keyboard
  }
};
return [{ json: { body } }];

// Show preset selection
const user_id = $('Classify').first().json.user_id;
const cb = $('HTTP schedule_presets').first().json;

const body = {
  chat_id: user_id,
  text: '📅 **Выбери пресет расписания:**',
  reply_markup: { inline_keyboard: cb.keyboard }
};
return [{ json: { body } }];

// Confirm preset change + show updated schedule
const user_id = $('Classify').first().json.user_id;
const updated = $('HTTP schedule (after set)').first().json;

const body = {
  chat_id: user_id,
  text: '✅ Пресет обновлён.\n\n' + updated.message,
  reply_markup: { inline_keyboard: updated.keyboard }
};
return [{ json: { body } }];

// Confirm reminder change + show updated schedule
const user_id = $('Classify').first().json.user_id;
const updated = $('HTTP schedule (after remind)').first().json;

const body = {
  chat_id: user_id,
  text: '🔔 Напоминание обновлено.\n\n' + updated.message,
  reply_markup: { inline_keyboard: updated.keyboard }
};
return [{ json: { body } }];

// Pause confirmation
const user_id = $('Classify').first().json.user_id;
const updated = $('HTTP schedule (after pause)').first().json;

const body = {
  chat_id: user_id,
  text: '⏸ Расписание на паузе.\n\n' + updated.message,
  reply_markup: { inline_keyboard: updated.keyboard }
};
return [{ json: { body } }];

// Resume confirmation
const user_id = $('Classify').first().json.user_id;
const updated = $('HTTP schedule (after resume)').first().json;

const body = {
  chat_id: user_id,
  text: '▶ Расписание возобновлено.\n\n' + updated.message,
  reply_markup: { inline_keyboard: updated.keyboard }
};
return [{ json: { body } }];

// Parse callback_data to action + value
const text = $json.text || '';
const user_id = String($json.user_id);
let action = 'unknown';
let value = null;

if (text.startsWith('sch_amount_')) {
  action = 'set_amount';
  value = text.replace('sch_amount_', '');
} else if (text.startsWith('sch_remind_')) {
  action = 'set_remind';
  value = text.replace('sch_remind_', '');
} else if (text.startsWith('sch_pause_')) {
  action = 'set_pause';
  value = text.replace('sch_pause_', '');
} else if (text.startsWith('sch_set_')) {
  action = 'set_preset';
  value = text.replace('sch_set_', '');
} else if (text === 'sch_presets') action = 'show_presets';
else if (text === 'sch_amounts') action = 'show_amounts';
else if (text === 'sch_reminders') action = 'show_reminders';
else if (text === 'sch_pauses') action = 'show_pauses';
else if (text === 'sch_resume') action = 'resume';
else if (text === 'sch_back') action = 'back';

return [{ json: { user_id, action, value, text } }];

