// Build Telegram reply from schedule_action result
const result = $input.first().json;
const classify = $('Classify').first().json;
const cq = classify.update?.callback_query;
if (!cq) {
  return [{ json: { error: 'no callback_query' }}];
}
const cb_id = cq.id;
const message_id = cq.message.message_id;
const chat_id = cq.message.chat.id;

if (!result.ok) {
  return [{ json: {
    method: 'answerCallbackQuery',
    callback_query_id: cb_id,
    text: result.message || 'Ошибка',
    show_alert: true,
  }}];
}

const msg = result.message || '';
const card = result.full_card;
const kb = result.keyboard || [];

// Use ONLY one: short confirm if no card update, or just card
const replyText = card || msg;

return [{ json: {
  method: 'editMessageText',
  chat_id: chat_id,
  message_id: message_id,
  text: replyText,
  reply_markup: { inline_keyboard: kb },
  callback_query_id: cb_id,
  callback_text: msg.startsWith('✅') ? 'Готово' : (msg.startsWith('⏸') ? 'Пауза' : ''),
}}];

const user_id = $('Classify').first().json.user_id;
const data = $('HTTP help').first().json;
const body = {
  chat_id: user_id,
  text: data.text,
  reply_markup: data.reply_markup,
  parse_mode: "Markdown"
};
return [{ json: { body } }];

